var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"Administration Reconstruction City        \\n<color=#ffd34c>KOREA </color>: SITE – 1 (old, SEOUL City)     \\n파이낸셜 타워 헬리포트","JPN":"Administration Reconstruction City        \\n<color=#ffd34c>JAPAN </color>: SITE – 1 (old, TOKYO City)     \\nファイナンシャルタワー・ヘリポート","ENG":"Administration Rebuilt City        \\n<color=#ffd34c>KOREA </color>: SITE – 1 (old, SEOUL City)     \\nFinancial Tower Heliport","TWN":"Administration Reconstruction City \\n<color=#ffd34c>KOREA </color>: SITE – 1 (old, SEOUL City) \\n金融塔直升機平臺"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"펜릴 소대원 유미나, 작전 대기 중         \\nCSE Level <b>2</b>        ","JPN":"フェンリル小隊員ヤナギ・ミナ、作戦待機中         \\nCSE Level <b>2</b>        ","ENG":"Yoo Mina of Fenrir Squad, standing by for the mission\\t\\nCSE Level <b>2</b>        ","TWN":"芬里爾小隊劉米娜，作戰待命中 \\nCSE Level <b>2</b>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"하아......","JPN":"はあ……","ENG":"Phew...","TWN":"哈……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"시간이 벌써 이렇게 됐나?","JPN":"もうこんな時間か。","ENG":"Is it time already?","TWN":"時間過得真快。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"어라?","JPN":"おや？","ENG":"Huh?","TWN":"咦？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"미나 양, 일찍 나오셨네요.","JPN":"ミナさん、はやいですね。","ENG":"You're early, Mina.","TWN":"米娜小姐，這麼早來啊。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"요즘은 항상 부지런하신걸요?","JPN":"最近はかなりの働き者ですね。","ENG":"You're so diligent these days!","TWN":"最近很勤快嘛。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아, 선배. 왔어?","JPN":"ああ、先輩。来たの？","ENG":"Oh, Shiyoon. You're here.","TWN":"啊，前輩。你來啦？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"한동안 쉬었으니까...... 그만큼 더 열심히 해야지.","JPN":"しばらく休んでいたから……その分頑張らないと。","ENG":"Well, I had a long break... I should work that much harder.","TWN":"我休息了一陣子……現在該認真工作了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하하, 좋은 마음가짐입니다.","JPN":"ハハハ、良い心構えです。","ENG":"Hah hah, that's a great attitude.","TWN":"哈哈，很好。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"미나 양도 이젠 정말 베테랑 카운터가 되신 것 같네요.","JPN":"ミナさんも、もうすっかりベテランカウンターの風格が出てきましたね。","ENG":"You seem to have become a full-fledged Counter now.","TWN":"米娜已經有資深制裁者的樣子了呢。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"처음 만났을 때 발목 잡지 말라며 투덜거리던 모습이 어제 일 같은데 말이죠.","JPN":"初めて会った時は足を引っ張らないで、とツンツンしていたのが昨日のことのようですが。","ENG":"It seems like just yesterday when you snarled at us not to try to control you.","TWN":"我還記的第一次見面的時候，你嫌棄地說要我別扯你後腿。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"왜, 왜 옛날 이야기를 하고 그래?!","JPN":"そ、そんな昔の話を言われても！","ENG":"W-why do you have to bring up the past?","TWN":"啊、幹嘛提以前的事情？！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"잘 모르면 그럴 수도 있지...... 남의 부끄러운 과거는 좀 잊어.","JPN":"何も知らなかった頃だし……人の恥ずかしい過去は忘れてほしいんだけど。","ENG":"I just didn't know any better... Could you just forget that ever happened?","TWN":"那時候太不懂事了嘛……別人的糗事就不要再提了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하하, 그렇게 강렬한 첫인사는 좀처럼 드물어서요.","JPN":"ハハハ、あんな強烈な初めましての挨拶は滅多にないものですから。","ENG":"Hah hah, I'm afraid you made quite the first impression.","TWN":"哈哈，因為你那時給我的第一印象太深刻了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"아마 스승님도 생생하게 기억하고 계실 겁니다.","JPN":"たぶん師匠もあの日のことは鮮明に覚えているでしょう。","ENG":"I'm sure even the Master remembers it vividly.","TWN":"我想師父也應該記憶猶新。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"으으...... 그래서 나만 보면 소대장이 잔소리가 심한 건가?","JPN":"うぅ……だから小隊長は私を見るたびにあんなに小言が多くなるのかな？","ENG":"Ugh... Is that why the Commander is always nagging at me?","TWN":"呃呃……所以，小隊長看到我才嘮叨個不停嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"좋게 생각하세요. 스승님께 관심을 받는 것도 쉬운 일은 아니거든요.","JPN":"前向きに考えましょう。師匠から関心を持ってもらうのも簡単なことではないので。","ENG":"Look on the bright side. It's not so easy to attract the Master's attention.","TWN":"你要往好處想，畢竟能得到師父的關注也不是容易的事。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그보다 오늘 작전 끝나고 부사장님께서 할 말이 있다고 하시던데요?","JPN":"それより今日の作戦が終わった後、副社長から話があると聞きましたよ？","ENG":"Anyway, I heard the Vice President has something to say after today's mission.","TWN":"對了，副總說，今天作戰結束後有話跟你說。"},"stage":{"bg":"MAINSTREAM_6100012","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"부사장님이?","JPN":"副社長が？","ENG":"She does?","TWN":"副總？"},"stage":{"bg":"MAINSTREAM_6100012","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"또 왜......? 나 최근에는 사고친 거 없는데.","JPN":"今度はなに……？　ここ最近は何かやらかした覚えはないのに。","ENG":"What now? I thought I'd stayed out of trouble lately.","TWN":"幹嘛……？我最近沒犯什麼錯啊。"},"stage":{"bg":"MAINSTREAM_6100012","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"탕비실에 있는 부식 집에 가져간다는 소문 때문이라면 그거 완전 뻥이라고.","JPN":"会社の休憩室のおやつを家に持ち帰ってるって話なら、全くデタラメの噂だからね。","ENG":"For the record, I never took the snacks from the break room home.","TWN":"如果是因為傳聞說我將休息室的零食偷回家的事情，那絕不是真的。"},"stage":{"bg":"MAINSTREAM_6100012","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"애초에 회사에서 먹으면 되는 걸 굳이 가져갈 이유가 없잖아?","JPN":"そもそも会社で食べればいい物を、家にわざわざ持ち帰る必要はないでしょう？","ENG":"Why would I do that when I can just have them at the office?","TWN":"零食在公司裡吃就好了，我幹嘛要大費周章帶回家？"},"stage":{"bg":"MAINSTREAM_6100012","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"아, 그건 저도 알고 있어요.","JPN":"ええ、それは僕もわかっていますよ。","ENG":"Oh, I know the rumor isn't true.","TWN":"啊，那件事我也聽說了。"},"stage":{"bg":"MAINSTREAM_6100012","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"클로에 씨가 재고 정리 실수한 걸 덮으려고 그런 보고서를 올린 것 같더라고요.","JPN":"クロエさんが在庫棚卸しのミスを誤魔化そうと、あんな報告書を出したそうです。","ENG":"It seems like Chloe was just trying to cover up the mistake she made while taking inventory.","TWN":"好像是克洛伊小姐為了推卸庫存管理失誤的責任，所以才提交了那種報告。"},"stage":{"bg":"MAINSTREAM_6100012","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"레나 씨에게 들켜서 크게 혼났으니 다음부터는 그런 일은 없을 겁니다.","JPN":"レナさんにバレてかなり怒られていたので、今後同じようなことはしないでしょう。","ENG":"Lena caught her forging records, so it won't happen again.","TWN":"蕾娜小姐已經狠狠教訓她了，以後不會再發生那樣的事情了。"},"stage":{"bg":"MAINSTREAM_6100012","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그, 그랬어? 어쩐지 클로에가 나만 보면 안색이 파래져서 도망가더라니......","JPN":"そ、そうだったの？　クロエが私に出くわすたびに、なぜか顔が真っ青になって逃げてておかしいと思ったら……","ENG":"I-is that what happened? No wonder Chloe was avoiding me like the plague...","TWN":"原來是這樣？怪不得克洛伊每次看到我臉色都怪怪的，還逃命似的跑了……"},"stage":{"bg":"MAINSTREAM_6100012","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"클로에 이 자식...... 돌아가면 가만 안 둘 줄 알아.","JPN":"クロエのやつ……帰ったらタダじゃおかないから！","ENG":"Chloe, that little brat. I'm going to kick her butt when I get back.","TWN":"克洛伊這傢伙……回去之後我一定要教訓她。"},"stage":{"bg":"MAINSTREAM_6100012","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"잠깐, 그럼 부사장님은 왜 날 보자는 거야?","JPN":"まって、ってことは副社長は何の用で私を？","ENG":"Wait, then why does the Vice President want to see me?","TWN":"等等，那副總為什麼找我呢？"},"stage":{"bg":"MAINSTREAM_6100012","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"글쎄요, 저도 잘은 모르지만......","JPN":"さあ、僕も詳しくはわかりませんが……","ENG":"Well, I'm not sure...","TWN":"這個嘛，我也不知道……"},"stage":{"bg":"MAINSTREAM_6100012","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"아마 미나 양에게도 나쁜 이야기는 아닐 것 같다는 예감이 드네요.","JPN":"おそらくミナさんにとって悪い話ではない予感がします。","ENG":"But I have a feeling it won't be bad news.","TWN":"不過我有預感，對米娜小姐來說應該不是什麼壞事。"},"stage":{"bg":"MAINSTREAM_6100012","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"흐음......","JPN":"ふーん……","ENG":"Hmm...","TWN":"嗯……"},"stage":{"bg":"MAINSTREAM_6100012","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그럼 기대해 봐도 되겠네.","JPN":"それじゃ、ちょっと期待してもいいかな。","ENG":"Then I guess I will look forward to it.","TWN":"那我就有點小期待了呢。"},"stage":{"bg":"MAINSTREAM_6100012","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"선배 예감은 꽤 잘 맞는 편이니까.","JPN":"先輩の予感は結構当たるから。","ENG":"Your hunches tend to be pretty accurate.","TWN":"因為前輩的預感通常都很靈驗。"},"stage":{"bg":"MAINSTREAM_6100012","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하하......?","JPN":"アハハ……！","ENG":"Oh? Hah hah...","TWN":"哈哈……？"},"stage":{"bg":"MAINSTREAM_6100012","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"이것 참, 미나 양도 사회생활 레벨이 꽤 오르신 것 같네요.","JPN":"いやー、ミナさんも社交辞令がかなりうまくなりましたね。","ENG":"I can tell you've been brushing up on your social skills.","TWN":"看來米娜小姐的人際交往能力提高了不少呢。"},"stage":{"bg":"MAINSTREAM_6100012","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"잡담이나 하고 있는 걸 보니 긴장이 풀려도 단단히 풀린 모양이군.","JPN":"くだらない雑談ばかりして、完全に気が抜けているようだな。","ENG":"You guys must be too relaxed if you're standing around making small talk.","TWN":"你們是放鬆過頭了吧，竟然有空閒聊。"},"stage":{"bg":"MAINSTREAM_6100013","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L1_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"아, 스승님. 오셨네요.","JPN":"お、師匠。お疲れ様です。","ENG":"Oh, Master. You're here.","TWN":"呃，師父，您來了。"},"stage":{"bg":"MAINSTREAM_6100013","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"소대장!","JPN":"小隊長！","ENG":"Commander!","TWN":"小隊長！"},"stage":{"bg":"MAINSTREAM_6100013","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"겁먹은 것보단 낫지만 방심하지는 말도록.","JPN":"怯えているよりはマシだが、あまり油断しないように。","ENG":"It's better than getting too nervous, but don't let your guard down.","TWN":"雖然不需要整天戰戰兢兢的，但也別太鬆懈。"},"stage":{"bg":"MAINSTREAM_6100013","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"특히 최근에는 침식체들이 더 강해지고 있다는 보고가 있으니까.","JPN":"この頃、侵食体がさらに強くなっているという報告がある。","ENG":"There have been several reports that the C.O.s have been getting stronger lately.","TWN":"根據報告，最近侵蝕體變得越來越強了。"},"stage":{"bg":"MAINSTREAM_6100013","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"예전에도 말했지만 실력이 조금 늘었다고 무모하게 날뛰는 애송이들까지 일일이 챙겨 줄 여유는 없어.","JPN":"前にも言ったが、調子に乗って無謀に暴れる若造の尻を拭うほど余裕はないぞ。","ENG":"As I've said before, I don't have the time to clean up after reckless amateurs who run to their own demise.","TWN":"以前我就說過，我沒精力照顧那些實力有所提高就驕傲自大的菜鳥。"},"stage":{"bg":"MAINSTREAM_6100013","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"걱정 마, 이젠 나도 그 때의 신입사원이 아니라고.","JPN":"心配しないで、私はもうあの時の新入社員じゃないから。","ENG":"Don't worry. I'm not the same rookie you knew.","TWN":"放心吧，我現在已經不是菜鳥了。"},"stage":{"bg":"MAINSTREAM_6100013","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하하, 스승님도 솔직하지 못하신 건 여전하네요.","JPN":"ハハハ、師匠も相変わらず素直じゃないですね。","ENG":"Hah hah, I see you're still lying to yourself, Master.","TWN":"哈哈，師父你還是這麼心口不一。"},"stage":{"bg":"MAINSTREAM_6100013","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그 무모한 신입이 위험에 빠졌을 때 몸을 던져 구해주시던 모습이 아직 기억에 선한데요.","JPN":"その無謀な新人が危険な目にあった時、体を張って救ってあげた姿がまだ記憶に残っていますよ。","ENG":"You're the one who ran in yourself to save a reckless rookie, if I remember correctly.","TWN":"我記得那個菜鳥陷入危險的時候，您奮不顧身營救的樣子。"},"stage":{"bg":"MAINSTREAM_6100013","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"......통신 상태가 불량하군.","JPN":"……通信状態がよくないな。","ENG":"... There must be something wrong with the connection.","TWN":"……現在通訊狀態不太好。"},"stage":{"bg":"MAINSTREAM_6100013","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"둘 다 빨리 탑승이나 하도록.","JPN":"雑談はここまでだ。2人とも搭乗するように。","ENG":"Just get on board, you two.","TWN":"你們兩個快點上來。"},"stage":{"bg":"MAINSTREAM_6100013","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"작전부, 관리국 교전지침은 내려왔나?","JPN":"作戦部、管理局からの交戦指針はまだか？","ENG":"Come in, Ops. Has the Administration cleared us to engage?","TWN":"作戰部，管理局下達交戰規則了嗎？"},"stage":{"bg":"MAINSTREAM_6100013","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"여기는 작전부, 레나입니다.","JPN":"こちらは作戦部、レナです。","ENG":"This is Lena, Operation Department.","TWN":"這裡是作戰部，我是蕾娜。"},"stage":{"bg":"MAINSTREAM_6100013","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L15_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"현재 카운터사이드 이펙트 레벨 2단계에서 계속 증가하고 있습니다.","JPN":"現在、カウンターサイドエフェクトレベル2段階からレベルが上昇し続けています。","ENG":"Currently, the CSE is at Level 2 and increasing.","TWN":"當前異界效應在2階段持續不斷增加。"},"stage":{"bg":"MAINSTREAM_6100013","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"또한 다수의 1종, 2종 침식체들이 외곽 지역에서 도심을 향해 이동 중입니다.","JPN":"さらに複数の第1種、2種の侵食体が外郭地域から都心に向かって移動中です。","ENG":"Moreover, multiple Category 1 and 2 C.O.s are moving towards downtown from the suburbs.","TWN":"發現多個1類及2類侵蝕體正在從周圍地區向城市中心移動。"},"stage":{"bg":"MAINSTREAM_6100013","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"최근 추세로 볼 때 제 3종 침식체의 등장 가능성도 높은 만큼, 관리국은 조속한 상황 종결을 희망하고 있습니다.","JPN":"最近の傾向から第3種侵食体が出現する可能性も高まった今、管理局は早急な状況終結を希望しています。","ENG":"Based on recent trends, it is highly likely that we'll see Category 3 as well. As such, the Administration hopes for a swift resolution.","TWN":"根據當前狀態來看，3類侵蝕體出現的可能性也非常高。因此管理局希望儘快結束戰鬥。"},"stage":{"bg":"MAINSTREAM_6100013","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"알겠다.","JPN":"了解。","ENG":"Copy that.","TWN":"收到。"},"stage":{"bg":"MAINSTREAM_6100013","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"펜릴 소대, 지금부터 작전 지역으로 강하한다.","JPN":"フェンリル小隊、これより作戦地域に降下する。","ENG":"Fenrir Squad ready for insertion.","TWN":"芬里爾小隊，現在開始向作戰地區降落。"},"stage":{"bg":"MAINSTREAM_6100013","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"작전부, 확인했습니다.","JPN":"作戦部、確認しました。","ENG":"Confirmed.","TWN":"作戰部，已確認。"},"stage":{"bg":"MAINSTREAM_6100013","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L21_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"즐거운 사냥 되시길 바랍니다.","JPN":"どうか、楽しい狩りを。","ENG":"Happy hunting.","TWN":"希望狩獵愉快。"},"stage":{"bg":"MAINSTREAM_6100013","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};